var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"부르셨나요, 주인어른? 배가 고프시다면 경단과 차를 내어올까요?","JPN":"お呼びでしょうか、主様。お腹が空かれたなら、お茶とお団子をお持ちしましょうか？","ENG":" Did you call me, Master? Shall I get you some dango and tea?","TWN":"您找我嗎，主人？肚子餓的話，要幫您準備糯米糰跟茶嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"네? 계약이라 함은, 저를 이곳에 묶어 두겠다는 말씀이신가요?","JPN":"はい？　契約ということは、私をこちらに従属させるということでしょうか？","ENG":" Pardon? A contract? Do you mean to tie me down here?","TWN":"這是？這契約是要把我綁在這裡的意思嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"후훗, 쓸데없는 걱정은 마시어요. 제가 주인어른을 버리고 어딜 가겠습니까?","JPN":"フフッ、余計な心配は無用でございます。私が主様を置いて、どこへ行くというのでしょうか。","ENG":" Don’t concern yourself with such matters, Master. I will never leave you.","TWN":"呵呵，主人多心了，我扔下主人是能去哪裡呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":" ...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"알고 있습니다. 주인어른께서는 목숨보다 대의를 소중히 여기는 분이시지요.","JPN":"承知しております。主様は命より大義を重んじる方であることを。","ENG":" I know you prioritize the noble cause over your own life, Master.","TWN":"我知道，比起性命，主人更在乎正義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"소생, 주인어른을 지키고자 하면 백 번도 목숨을 바칠 수 있사옵니다.","JPN":"私は、主様を守れるのなら、何度でもこの命を捧げることができます。","ENG":" I’m willing to die a thousand times for you.","TWN":"小的，想要守護主人，就算要獻出性命也在所不惜。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"허나 제 목숨이 아닌 주인어른의 목숨이 걸린 일이라면……","JPN":"しかし私の命ではなく、主様の命がかかったことでしたら……","ENG":" But if it’s your life not mine that is at stake...","TWN":"但若是要犧牲的不是我的性命，而是主人的……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"저는 주인어른의 신의를 저버리게 될지도 모릅니다.","JPN":"私は主様の信義を裏切ることになるかもしれませぬ。","ENG":" I might betray your faith.","TWN":"那我很可能會辜負主人的信任。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그러니 대의를 위해 스스로를 희생하셔야 할 때가 온다면, 부디 저를 먼저 치시어요.","JPN":"ですので大義のために自らを犠牲にしなければならない時が来たら、どうか私を真っ先に見放してくださいませ。","ENG":" So if you ever have to sacrifice yourself, even for for a noble cause, please slay me first.","TWN":"因此，若是有一天，主人必須犧牲小我完成大我，到那時請務必先除掉我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"소생은 주인어른께서 어떤 선택을 내리건, 소중한 분을 지킬 뿐이랍니다.","JPN":"私は主様がどんな決断を下しても、大切な方を守るのみです。","ENG":" Whatever your choice make, I will protect the most precious person I have.","TWN":"因為無論主人做出怎樣的選擇，我都只想保護對我而言最重要那個人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"…….","JPN":" ……","ENG":" ...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"말씀 끝나셨으면, 향이 좋은 녹차를 내어오지요.","JPN":"お話が終わったのでしたら、香りの良いお茶をご用意いたしまする。","ENG":" If you’re finished, let me get you a cup of green tea.","TWN":"談話結束的話，請容我去端杯茶香四溢的綠茶來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};